"use client"

import { useEffect, useMemo, useState } from "react"
import { useRouter } from "next/navigation"
import { useAuthStore } from "@/store/auth-store"
import { useDataStore } from "@/store/data-store"
import { OperationsMap } from "@/components/maps/operations-map"
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card"
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select"
import { Button } from "@/components/ui/button"
import { Loader2, MapPinned } from "lucide-react"
import {
  Bar,
  BarChart,
  CartesianGrid,
  Cell,
  Pie,
  PieChart,
  ResponsiveContainer,
  Tooltip,
  XAxis,
  YAxis,
} from "recharts"

type DateFilter = "all" | "today" | "7d" | "30d" | "90d"

const DATE_FILTERS: { value: DateFilter; label: string }[] = [
  { value: "all", label: "All time" },
  { value: "today", label: "Today" },
  { value: "7d", label: "Last 7 days" },
  { value: "30d", label: "Last 30 days" },
  { value: "90d", label: "Last 90 days" },
]

const STATUS_LABELS: Record<string, string> = {
  new: "New",
  assigned: "Assigned",
  in_progress: "In Progress",
  pending_approval: "Awaiting DMA",
  approved: "Approved",
  rejected: "Rework",
  closed: "Closed",
}

const STATUS_COLORS: Record<string, string> = {
  new: "#ef4444",
  assigned: "#f59e0b",
  in_progress: "#0ea5e9",
  pending_approval: "#8b5cf6",
  approved: "#10b981",
  rejected: "#f97316",
  closed: "#334155",
}

const PRIORITY_COLORS: Record<string, string> = {
  low: "#22c55e",
  medium: "#f59e0b",
  high: "#ef4444",
  critical: "#7c3aed",
}

function getFieldOwnerName(report: {
  assignedEngineerName?: string | null
  teamLeaderName?: string | null
  teamName?: string | null
}) {
  return (
    report.assignedEngineerName?.trim() ||
    report.teamLeaderName?.trim() ||
    report.teamName?.trim() ||
    "Unassigned field team"
  )
}

function passesDateFilter(dateValue: string | undefined, filter: DateFilter) {
  if (filter === "all") return true
  if (!dateValue) return false

  const created = new Date(dateValue)
  if (Number.isNaN(created.getTime())) return false

  const now = new Date()
  const startOfToday = new Date(now.getFullYear(), now.getMonth(), now.getDate())
  const diffMs = now.getTime() - created.getTime()
  const diffDays = diffMs / 86_400_000

  switch (filter) {
    case "today":
      return created >= startOfToday
    case "7d":
      return diffDays <= 7
    case "30d":
      return diffDays <= 30
    case "90d":
      return diffDays <= 90
    default:
      return true
  }
}

function formatScopeLabel(report: {
  dmaName?: string | null
  districtName?: string | null
  utilityName?: string | null
  regionName?: string | null
}) {
  if (report.dmaName?.trim()) return report.dmaName
  if (report.districtName?.trim()) return report.districtName
  if (report.utilityName?.trim()) return report.utilityName
  if (report.regionName?.trim()) return report.regionName
  return "Unassigned area"
}

export default function MapPage() {
  const router = useRouter()
  const { currentUser } = useAuthStore()
  const { utilities, dmas, reports, fetchUtilities, fetchDMAs, fetchReports } = useDataStore()

  const [loading, setLoading] = useState(true)
  const [dateFilter, setDateFilter] = useState<DateFilter>("30d")
  const [selectedUtilityId, setSelectedUtilityId] = useState("all")
  const [selectedDMAId, setSelectedDMAId] = useState("all")
  const [selectedOwner, setSelectedOwner] = useState("all")
  const [selectedReporter, setSelectedReporter] = useState("all")

  const isAdmin = currentUser?.role === "admin"
  const isUtility = currentUser?.role === "utility_manager"
  const isDMA = currentUser?.role === "dma_manager"

  useEffect(() => {
    async function loadData() {
      if (!currentUser) return

      setLoading(true)
      try {
        await Promise.all([
          fetchUtilities(),
          fetchDMAs(isUtility ? currentUser.utilityId ?? undefined : undefined),
          fetchReports(
            isDMA
              ? { dmaId: currentUser.dmaId ?? "" }
              : isUtility
                ? { utilityId: currentUser.utilityId ?? "" }
                : undefined
          ),
        ])
      } finally {
        setLoading(false)
      }
    }

    void loadData()
  }, [currentUser, fetchDMAs, fetchReports, fetchUtilities, isDMA, isUtility])

  const currentDMA = useMemo(
    () => dmas.find((dma) => dma.id === currentUser?.dmaId) ?? null,
    [currentUser?.dmaId, dmas]
  )

  useEffect(() => {
    if (isUtility && currentUser?.utilityId) {
      setSelectedUtilityId(currentUser.utilityId)
    }
  }, [currentUser?.utilityId, isUtility])

  useEffect(() => {
    if (isDMA && currentUser?.dmaId) {
      setSelectedDMAId(currentUser.dmaId)
      if (currentDMA?.utilityId) {
        setSelectedUtilityId(currentDMA.utilityId)
      }
    }
  }, [currentDMA?.utilityId, currentUser?.dmaId, isDMA])

  const visibleUtilities = useMemo(() => {
    if (isUtility && currentUser?.utilityId) {
      return utilities.filter((utility) => utility.id === currentUser.utilityId)
    }

    if (isDMA && currentDMA?.utilityId) {
      return utilities.filter((utility) => utility.id === currentDMA.utilityId)
    }

    return utilities
  }, [currentDMA?.utilityId, currentUser?.utilityId, isDMA, isUtility, utilities])

  const visibleDMAs = useMemo(() => {
    const base = isDMA && currentUser?.dmaId
      ? dmas.filter((dma) => dma.id === currentUser.dmaId)
      : dmas

    if (selectedUtilityId === "all") {
      return base
    }

    return base.filter((dma) => dma.utilityId === selectedUtilityId)
  }, [currentUser?.dmaId, dmas, isDMA, selectedUtilityId])

  useEffect(() => {
    if (selectedDMAId !== "all" && !visibleDMAs.some((dma) => dma.id === selectedDMAId)) {
      setSelectedDMAId("all")
    }
  }, [selectedDMAId, visibleDMAs])

  const scopedReports = useMemo(() => {
    if (!currentUser) return []
    if (isAdmin) return reports
    if (isUtility && currentUser.utilityId) {
      return reports.filter((report) => report.utilityId === currentUser.utilityId)
    }
    if (isDMA && currentUser.dmaId) {
      return reports.filter((report) => report.dmaId === currentUser.dmaId)
    }
    return []
  }, [currentUser, isAdmin, isDMA, isUtility, reports])

  const filteredReports = useMemo(() => {
    return scopedReports.filter((report) => {
      const matchesDate = passesDateFilter(report.createdAt, dateFilter)
      const matchesUtility = selectedUtilityId === "all" ? true : report.utilityId === selectedUtilityId
      const matchesDMA = selectedDMAId === "all" ? true : report.dmaId === selectedDMAId
      const owner = getFieldOwnerName(report)
      const matchesOwner = selectedOwner === "all" ? true : owner === selectedOwner
      const reporter = report.reporterName?.trim() || "Anonymous"
      const matchesReporter = selectedReporter === "all" ? true : reporter === selectedReporter
      return matchesDate && matchesUtility && matchesDMA && matchesOwner && matchesReporter
    })
  }, [dateFilter, scopedReports, selectedDMAId, selectedOwner, selectedReporter, selectedUtilityId])

  const reportsWithCoordinates = useMemo(
    () =>
      filteredReports.filter(
        (report) =>
          Number.isFinite(report.latitude) &&
          Number.isFinite(report.longitude) &&
          !(report.latitude === 0 && report.longitude === 0)
      ),
    [filteredReports]
  )

  const ownerOptions = useMemo(() => {
    return Array.from(new Set(filteredReports.map((report) => getFieldOwnerName(report)))).sort()
  }, [filteredReports])

  const reporterOptions = useMemo(() => {
    return Array.from(
      new Set(filteredReports.map((report) => report.reporterName?.trim() || "Anonymous"))
    ).sort()
  }, [filteredReports])

  const activeUtilityId = useMemo(() => {
    if (selectedUtilityId !== "all") return selectedUtilityId
    if (isUtility) return currentUser?.utilityId ?? null
    return currentDMA?.utilityId ?? null
  }, [currentDMA?.utilityId, currentUser?.utilityId, isUtility, selectedUtilityId])

  const activeUtility = useMemo(
    () => utilities.find((utility) => utility.id === activeUtilityId) ?? null,
    [activeUtilityId, utilities]
  )

  const activeDMA = useMemo(
    () => dmas.find((dma) => dma.id === selectedDMAId) ?? null,
    [dmas, selectedDMAId]
  )

  const mapCenter = useMemo<[number, number] | null>(() => {
    if (
      activeDMA &&
      Number.isFinite(activeDMA.centerLatitude) &&
      Number.isFinite(activeDMA.centerLongitude)
    ) {
      return [Number(activeDMA.centerLatitude), Number(activeDMA.centerLongitude)]
    }

    if (
      activeUtility &&
      Number.isFinite(activeUtility.centerLatitude) &&
      Number.isFinite(activeUtility.centerLongitude)
    ) {
      return [Number(activeUtility.centerLatitude), Number(activeUtility.centerLongitude)]
    }

    return null
  }, [activeDMA, activeUtility])

  const totalReports = filteredReports.length
  const repairedReports = filteredReports.filter((report) =>
    ["approved", "closed"].includes(report.status)
  ).length
  const urgentReports = filteredReports.filter(
    (report) =>
      ["high", "critical"].includes(report.priority) &&
      !["approved", "closed"].includes(report.status)
  ).length
  const unattendedReports = filteredReports.filter((report) => {
    const hasOwner = Boolean(
      report.teamId || report.teamName || report.teamLeaderName || report.assignedEngineerName
    )
    return !["approved", "closed"].includes(report.status) && (!hasOwner || report.status === "new")
  }).length

  const statusChartData = useMemo(
    () =>
      Object.keys(STATUS_LABELS)
        .map((statusKey) => ({
          name: STATUS_LABELS[statusKey],
          value: filteredReports.filter((report) => report.status === statusKey).length,
          color: STATUS_COLORS[statusKey],
        }))
        .filter((item) => item.value > 0),
    [filteredReports]
  )

  const priorityChartData = useMemo(
    () =>
      ["low", "medium", "high", "critical"]
        .map((priorityKey) => ({
          name: priorityKey === "medium" ? "Moderate" : priorityKey.charAt(0).toUpperCase() + priorityKey.slice(1),
          value: filteredReports.filter((report) => report.priority === priorityKey).length,
          color: PRIORITY_COLORS[priorityKey],
        }))
        .filter((item) => item.value > 0),
    [filteredReports]
  )

  if (loading && !reports.length) {
    return (
      <div className="flex min-h-[70vh] items-center justify-center">
        <div className="flex items-center gap-3 rounded-full border border-slate-200 bg-white px-5 py-3 text-sm font-medium text-slate-600 shadow-sm">
          <Loader2 className="h-4 w-4 animate-spin" />
          Loading live map desk...
        </div>
      </div>
    )
  }

  return (
    <div className="space-y-6">
      <section className="rounded-[30px] border border-slate-200/80 bg-white px-6 py-5 shadow-[0_24px_80px_-60px_rgba(15,23,42,0.28)]">
        <div className="flex flex-wrap items-start justify-between gap-6">
          <div className="space-y-2">
            <div className="flex items-center gap-2 text-xs font-semibold uppercase tracking-[0.24em] text-cyan-700">
              <MapPinned className="h-4 w-4" />
              Live monitoring
            </div>
            <h1 className="text-3xl font-semibold tracking-tight text-slate-900">Leak Monitoring Map</h1>
            <p className="max-w-3xl text-sm leading-6 text-slate-600">
              Keep the familiar GIS-style monitoring experience while staying inside the full MajiScope
              workflow. Filter by date, utility, DMA, field owner, or reporter, then open any leak directly
              from the map.
            </p>
          </div>

          <div className="rounded-[24px] border border-slate-200 bg-slate-50 px-4 py-3">
            <div className="text-xs font-semibold uppercase tracking-[0.2em] text-slate-500">
              Active scope
            </div>
            <div className="mt-2 text-2xl font-semibold text-slate-900">
              {activeDMA?.name || activeUtility?.name || "National operations view"}
            </div>
            <p className="mt-1 text-sm text-slate-600">
              {reportsWithCoordinates.length} plotted leak points in the current view
            </p>
          </div>
        </div>
      </section>

      <Card className="rounded-[24px] border-slate-200/80 shadow-[0_20px_70px_-58px_rgba(15,23,42,0.32)]">
        <CardContent className="p-3.5">
          <div className="grid gap-2 md:grid-cols-2 xl:grid-cols-[140px_160px_160px_170px_170px_auto] xl:items-center">
            <Select value={dateFilter} onValueChange={(value) => setDateFilter(value as DateFilter)}>
              <SelectTrigger className="h-9 rounded-xl px-3 text-sm">
                <SelectValue placeholder="Date filter" />
              </SelectTrigger>
              <SelectContent>
                {DATE_FILTERS.map((filter) => (
                  <SelectItem key={filter.value} value={filter.value}>
                    {filter.label}
                  </SelectItem>
                ))}
              </SelectContent>
            </Select>

            <Select
              value={selectedUtilityId}
              onValueChange={setSelectedUtilityId}
              disabled={!isAdmin || !visibleUtilities.length}
            >
              <SelectTrigger className="h-9 rounded-xl px-3 text-sm">
                <SelectValue placeholder="Utility / Region" />
              </SelectTrigger>
              <SelectContent>
                <SelectItem value="all">All utilities</SelectItem>
                {visibleUtilities.map((utility) => (
                  <SelectItem key={utility.id} value={utility.id}>
                    {utility.name}
                  </SelectItem>
                ))}
              </SelectContent>
            </Select>

            <Select
              value={selectedDMAId}
              onValueChange={setSelectedDMAId}
              disabled={isDMA || !visibleDMAs.length}
            >
              <SelectTrigger className="h-9 rounded-xl px-3 text-sm">
                <SelectValue placeholder="DMA / District" />
              </SelectTrigger>
              <SelectContent>
                <SelectItem value="all">All DMAs</SelectItem>
                {visibleDMAs.map((dma) => (
                  <SelectItem key={dma.id} value={dma.id}>
                    {dma.name}
                  </SelectItem>
                ))}
              </SelectContent>
            </Select>

            <Select value={selectedOwner} onValueChange={setSelectedOwner}>
              <SelectTrigger className="h-9 rounded-xl px-3 text-sm">
                <SelectValue placeholder="Field owner" />
              </SelectTrigger>
              <SelectContent>
                <SelectItem value="all">All field owners</SelectItem>
                {ownerOptions.map((owner) => (
                  <SelectItem key={owner} value={owner}>
                    {owner}
                  </SelectItem>
                ))}
              </SelectContent>
            </Select>

            <Select value={selectedReporter} onValueChange={setSelectedReporter}>
              <SelectTrigger className="h-9 rounded-xl px-3 text-sm">
                <SelectValue placeholder="Reporter" />
              </SelectTrigger>
              <SelectContent>
                <SelectItem value="all">All reporters</SelectItem>
                {reporterOptions.map((reporter) => (
                  <SelectItem key={reporter} value={reporter}>
                    {reporter}
                  </SelectItem>
                ))}
              </SelectContent>
            </Select>

            <Button
              type="button"
              variant="outline"
              className="h-9 justify-self-start rounded-xl px-3 text-sm xl:justify-self-end"
              onClick={() => {
                setDateFilter("30d")
                setSelectedUtilityId(isUtility ? currentUser?.utilityId ?? "all" : isDMA ? currentDMA?.utilityId ?? "all" : "all")
                setSelectedDMAId(isDMA ? currentUser?.dmaId ?? "all" : "all")
                setSelectedOwner("all")
                setSelectedReporter("all")
              }}
            >
              Reset view
            </Button>
          </div>
        </CardContent>
      </Card>

      <div className="flex flex-col gap-4 xl:flex-row xl:items-start">
        <div className="min-w-0 flex-1">
          <OperationsMap
            reports={reportsWithCoordinates.map((report) => ({
              id: report.id,
              trackingId: report.trackingId,
              description: report.description,
              latitude: report.latitude,
              longitude: report.longitude,
              status: report.status,
              priority: report.priority,
              dmaName: report.dmaName,
              utilityName: report.utilityName,
              regionName: report.regionName,
              districtName: report.districtName,
              address: report.address,
              reporterName: report.reporterName,
            }))}
            center={mapCenter}
            networkPreviewUrl={activeUtility?.pipeNetworkPreviewUrl}
            networkFileName={activeUtility?.pipeNetworkFileName}
            title={activeDMA?.name || activeUtility?.name || "National leak monitoring map"}
            description="The map frames the actual visible leak points automatically, keeps the pipe network optional, and lets users open a report directly from the map."
            onReportSelect={(reportId) => router.push(`/dashboard/reports/${reportId}`)}
          />
        </div>

        <div className="w-full space-y-4 xl:w-[280px] xl:flex-none">
          <Card className="rounded-[28px] border-slate-200/80 shadow-[0_24px_80px_-56px_rgba(15,23,42,0.45)]">
            <CardHeader className="pb-2">
              <CardTitle className="text-lg">Current monitoring totals</CardTitle>
            </CardHeader>
            <CardContent className="grid grid-cols-2 gap-3">
              <div className="rounded-2xl bg-slate-50 px-4 py-3">
                <div className="text-[11px] font-semibold uppercase tracking-[0.18em] text-slate-500">Total</div>
                <div className="mt-1 text-2xl font-semibold text-slate-900">{totalReports}</div>
              </div>
              <div className="rounded-2xl bg-emerald-50 px-4 py-3">
                <div className="text-[11px] font-semibold uppercase tracking-[0.18em] text-emerald-700">Repaired</div>
                <div className="mt-1 text-2xl font-semibold text-emerald-900">{repairedReports}</div>
              </div>
              <div className="rounded-2xl bg-rose-50 px-4 py-3">
                <div className="text-[11px] font-semibold uppercase tracking-[0.18em] text-rose-700">Urgent</div>
                <div className="mt-1 text-2xl font-semibold text-rose-900">{urgentReports}</div>
              </div>
              <div className="rounded-2xl bg-amber-50 px-4 py-3">
                <div className="text-[11px] font-semibold uppercase tracking-[0.18em] text-amber-700">Unattended</div>
                <div className="mt-1 text-2xl font-semibold text-amber-900">{unattendedReports}</div>
              </div>
            </CardContent>
          </Card>

          <Card className="rounded-[28px] border-slate-200/80 shadow-[0_24px_80px_-56px_rgba(15,23,42,0.45)]">
            <CardHeader className="pb-2">
              <CardTitle className="text-lg">Leaks by status</CardTitle>
            </CardHeader>
            <CardContent className="h-[250px]">
              <ResponsiveContainer width="100%" height="100%">
                <BarChart data={statusChartData} layout="vertical" margin={{ top: 8, right: 12, left: 0, bottom: 8 }}>
                  <CartesianGrid strokeDasharray="3 3" horizontal={false} stroke="#e2e8f0" />
                  <XAxis type="number" allowDecimals={false} stroke="#64748b" fontSize={11} />
                  <YAxis dataKey="name" type="category" width={96} stroke="#475569" fontSize={11} />
                  <Tooltip cursor={{ fill: "#f8fafc" }} />
                  <Bar dataKey="value" radius={[0, 10, 10, 0]}>
                    {statusChartData.map((entry) => (
                      <Cell key={entry.name} fill={entry.color} />
                    ))}
                  </Bar>
                </BarChart>
              </ResponsiveContainer>
            </CardContent>
          </Card>

          <Card className="rounded-[28px] border-slate-200/80 shadow-[0_24px_80px_-56px_rgba(15,23,42,0.45)]">
            <CardHeader className="pb-2">
              <CardTitle className="text-lg">Leaks by priority</CardTitle>
            </CardHeader>
            <CardContent className="h-[230px]">
              <ResponsiveContainer width="100%" height="100%">
                <PieChart>
                  <Pie
                    data={priorityChartData}
                    dataKey="value"
                    nameKey="name"
                    innerRadius={52}
                    outerRadius={88}
                    paddingAngle={4}
                  >
                    {priorityChartData.map((entry) => (
                      <Cell key={entry.name} fill={entry.color} />
                    ))}
                  </Pie>
                  <Tooltip />
                </PieChart>
              </ResponsiveContainer>
              <div className="mt-3 flex flex-wrap gap-2">
                {priorityChartData.map((entry) => (
                  <div key={entry.name} className="flex items-center gap-2 rounded-full bg-slate-50 px-3 py-1.5 text-xs font-medium text-slate-700">
                    <span className="h-2.5 w-2.5 rounded-full" style={{ backgroundColor: entry.color }} />
                    {entry.name} ({entry.value})
                  </div>
                ))}
              </div>
            </CardContent>
          </Card>

        </div>
      </div>
    </div>
  )
}
